+import test from 'node:test';
+import assert from 'node:assert/strict';
+import { mkdtemp, mkdir, writeFile } from 'node:fs/promises';
+import { tmpdir } from 'node:os';
+import { join } from 'node:path';
+
+import { buildSourceMap, collectIngestStatus } from './ingest-status.js';
+
+test('buildSourceMap extracts raw path to source page mapping from frontmatter', async () => {
+  const root = await mkdtemp(join(tmpdir(), 'ingest-status-'));
+  const sourcesDir = join(root, 'wiki', 'sources');
+  await mkdir(sourcesDir, { recursive: true });
+
+  await writeFile(
+    join(sourcesDir, 'ai-builders-2026-04-21.md'),
+    `---
+title: "ai-builders-2026-04-21"
+type: source
+tags: [来源]
+sources: [raw/05-ai-builders/2026-04-21/digest-zh.md]
+last_updated: 2026-04-21
+---
+
+## 核心摘要
+test
+`,
+    'utf-8'
+  );
+
+  const sourceMap = await buildSourceMap(sourcesDir);
+
+  assert.deepEqual(sourceMap, {
+    'raw/05-ai-builders/2026-04-21/digest-zh.md': 'ai-builders-2026-04-21',
+  });
+});
+
+test('collectIngestStatus groups files into unprocessed, processed, batch-entry, and updatable', async () => {
+  const root = await mkdtemp(join(tmpdir(), 'ingest-status-'));
+  const rawDir = join(root, 'raw');
+  const sourcesDir = join(root, 'wiki', 'sources');
+
+  await mkdir(join(rawDir, '01-articles'), { recursive: true });
+  await mkdir(join(rawDir, '05-ai-builders', '2026-04-21'), { recursive: true });
+  await mkdir(join(rawDir, '09-archive'), { recursive: true });
+  await mkdir(sourcesDir, { recursive: true });
+
+  await writeFile(join(rawDir, '01-articles', 'new-note.md'), '# article', 'utf-8');
+  await writeFile(join(rawDir, '05-ai-builders', '2026-04-21', 'digest-zh.md'), '# digest', 'utf-8');
+  await writeFile(join(rawDir, '05-ai-builders', '2026-04-21', 'feed-x.json'), '{}', 'utf-8');
+  await writeFile(join(rawDir, '09-archive', 'ignored.md'), '# ignore', 'utf-8');
+
+  await writeFile(
+    join(sourcesDir, 'ai-builders-2026-04-21.md'),
+    `---
+title: "ai-builders-2026-04-21"
+type: source
+tags: [来源]
+sources: [raw/05-ai-builders/2026-04-21/digest-zh.md]
+last_updated: 2026-04-21
+---
+
+## 核心摘要
+test
+`,
+    'utf-8'
+  );
+
+  const status = await collectIngestStatus(root);
+
+  assert.deepEqual(status.unprocessed, ['raw/01-articles/new-note.md']);
+  assert.deepEqual(status.processed, [
+    {
+      rawPath: 'raw/05-ai-builders/2026-04-21/digest-zh.md',
+      sourcePage: 'ai-builders-2026-04-21',
+    },
+  ]);
+  assert.deepEqual(status.batchEntries, ['raw/05-ai-builders/2026-04-21/digest-zh.md']);
+  assert.deepEqual(status.updatable, [
+    {
+      rawPath: 'raw/05-ai-builders/2026-04-21/digest-zh.md',
+      sourcePage: 'ai-builders-2026-04-21',
+    },
+  ]);
+});
